SELECT t.id, t.author, t.assignee, t.title, t.detail, t.created_at AS createdAt, t.updated_at AS updatedAt, t.status, t.priority, t.start_date AS startDate, t.due_date AS deadline, t.user_id AS userId, c.id AS categoryId, c.name AS categoryName, c.color AS categoryColor FROM todos t LEFT JOIN groups c ON t.group_id = c.id
t.user_id = #{userId}
AND t.title LIKE CONCAT('%', #{keyword}, '%')
AND t.group_id = #{categoryId}
AND t.status != 'COMPLETED'
ORDER BY
t.title t.status t.priority t.due_date t.created_at
ASC DESC
LIMIT #{limit} OFFSET #{offset}

