SELECT COUNT(*) AS totalCount, SUM(CASE WHEN status = 'NOT_STARTED' THEN 1 ELSE 0 END) AS notStartedCount, SUM(CASE WHEN status = 'IN_PROGRESS' THEN 1 ELSE 0 END) AS inProgressCount, SUM(CASE WHEN status = 'COMPLETED' THEN 1 ELSE 0 END) AS completedCount, SUM(CASE WHEN status != 'COMPLETED' THEN 1 ELSE 0 END) AS incompleteCount FROM todos
